  miniProject:{title:'Internship Student Portal — React Frontend',description:'Complete React frontend for the internship management platform.',requirements:['Login and Register forms with validation','Protected routes using AuthContext','Student dashboard with real API data','Student list with filter, search, pagination','Student profile page with edit form','Course list and enrollment','Profile photo upload UI','Responsive design with CSS/Tailwind','Connect to Spring Boot API with Axios interceptors','Loading states and error handling throughout']}
