  miniProject:{title:'Capstone — Full Stack Internship Platform',description:'Build, deploy, and present a complete full-stack application demonstrating all 9 weeks of learning.',requirements:['Full-stack app: Spring Boot API + React frontend','JWT authentication with register/login','At least 3 entities with relationships','Full CRUD for main entity','Role-based access control','Responsive React UI','Deployed on Render (API) + Vercel (frontend)','GitHub repo with clean README','3-5 minute demo video','Postman collection exported','Certificate awarded on review']}
