// Write all weeks to the main data file
const fs2 = require('fs');
const path2 = require('path');
const out = path2.join(__dirname, '..', 'public', 'course-data-java-fullstack.js');

// Convert objects to JS string via JSON then clean it up
const allWeeks = [week6, week7, week8, week9];

let toAppend = '';
for (const w of allWeeks) {
  toAppend += JSON.stringify(w, null, 2)
    .replace(/"([^"]+)":/g, '$1:')  // unquote keys
    .replace(/"/g, "'") + ',\n';
}

// Close the weeks array and the main object
toAppend += `
  ] // end weeks
}; // end JAVA_FULLSTACK

// Export for use in dashboard
if (typeof module !== 'undefined') module.exports = JAVA_FULLSTACK;
`;

fs2.appendFileSync(out, toAppend);
console.log('All weeks appended and file closed!');
console.log('Final file size:', fs2.statSync(out).size, 'bytes');
